  ::-webkit-scrollbar{ width:8px; }
  ::-webkit-scrollbar-thumb{ background:#3a3f52; border-radius:4px; }

  select.tell-select{
    background:#12141b;
    border:1px solid var(--border);
    color:var(--text);
    border-radius:8px;
    padding:6px 6px;
    font-size:12px;
    width:118px;
    flex-shrink:0;
  }

  .sound-panel{
    display:flex;
    align-items:center;
    gap:14px;
    flex-wrap:wrap;
    justify-content:center;
    font-size:13px;
    color:var(--sub);
    background:var(--panel);
    border:1px solid var(--border);
    border-radius:12px;
    padding:10px 16px;
  }
  .sound-panel label{ display:flex; align-items:center; gap:6px; }
  .sound-panel input[type=range]{ width:100px; }

  #tellOverlay{
    position:fixed;
    inset:0;
    pointer-events:none;
    z-index:50;
    display:flex;
    align-items:center;
    justify-content:center;
    opacity:0;
  }
  #tellOverlay.show-rolling{
    animation: rollingFlash .9s ease-out;
  }
  #tellOverlay.show-atsui{
    animation: atsuiFlash 1.1s ease-out;
  }
  #tellOverlay .tell-text{
    font-size:56px;
    font-weight:900;
    letter-spacing:4px;
    text-shadow:0 0 20px rgba(0,0,0,.8);
  }
  #tellOverlay.show-rolling .tell-text{ color:var(--accent2); }
  #tellOverlay.show-atsui .tell-text{ color:#ffd23f; font-size:68px; }

  @keyframes rollingFlash{
    0%{ opacity:0; }
    15%{ opacity:1; background:rgba(93,169,255,0.12); }
    100%{ opacity:0; }
  }
  @keyframes atsuiFlash{
    0%{ opacity:0; transform:scale(.8); }
    10%{ opacity:1; transform:scale(1.05); background:rgba(255,80,50,0.18); }
    30%{ transform:scale(1); }
    100%{ opacity:0; }
  }
</style>
