<div id="tellOverlay"><div class="tell-text"></div></div>

<h1>🎯 ルーレット作成アプリ</h1>

<div class="layout">

  <div class="wheel-side">
    <div class="wheel-wrap">
      <div id="pointer"></div>
      <canvas id="wheel" width="360" height="360"></canvas>
    </div>
    <button id="spinBtn">スピン！</button>
    <div id="result"></div>

    <div class="sound-panel">
      <label><input type="checkbox" id="tellEnabled" checked> 先バレ演出</label>
      <label>🔊 <input type="range" id="tellVolume" min="0" max="100" value="70"></label>
    </div>

    <div class="history">
      <h3>結果履歴</h3>
      <ul id="historyList"></ul>
    </div>
  </div>

  <div class="panel">
    <h2>項目の設定</h2>

    <div class="quick-row">
      <input type="number" id="quickCount" min="2" max="30" value="4">
      <button id="quickGenBtn">個数を指定して作り直す</button>
    </div>

    <div id="itemList"></div>

    <div class="add-row">
      <button id="addBtn">＋ 項目を追加</button>
      <button id="resetBtn" style="background:var(--panel2);color:var(--text);border:1px solid var(--border);">初期化</button>
    </div>

    <div class="total-note" id="totalNote"></div>
  </div>

</div>

