input.new_string:
const DEFAULT_ITEMS = [
  {name:"当たり", weight:1, tell:"rolling"},
  {name:"はずれ", weight:3, tell:"none"},
  {name:"もう一回", weight:2, tell:"rolling"},
  {name:"大当たり", weight:1, tell:"atsui"},
];

const TELL_SOUNDS = {
  none:   { label:"なし",             src:null },
  rolling:{ label:"ローリング(通常)",  src:"audio/index2_rolling.mp3" },
  atsui:  { label:"激熱(ポキューン)",  src:"audio/pokyun_atsui.mp3" },
};
const tellAudioCache = {};
function getTellAudio(key){
  if(key === "none") return null;
  if(!tellAudioCache[key]){
    tellAudioCache[key] = new Audio(TELL_SOUNDS[key].src);
    tellAudioCache[key].preload = "auto";
  }
  return tellAudioCache[key];
}

const tellEnabledEl = document.getElementById("tellEnabled");
const tellVolumeEl = document.getElementById("tellVolume");
const tellOverlay = document.getElementById("tellOverlay");
const tellOverlayText = tellOverlay.querySelector(".tell-text");

function playTell(key){
  if(key === "none" || !tellEnabledEl.checked) return;
  const audio = getTellAudio(key);
  if(!audio) return;
  audio.volume = Number(tellVolumeEl.value) / 100;
  audio.currentTime = 0;
  audio.play().catch(()=>{});

  tellOverlay.classList.remove("show-rolling","show-atsui");
  void tellOverlay.offsetWidth; // restart animation
  if(key === "atsui"){
    tellOverlayText.textContent = "熱っ!?";
    tellOverlay.classList.add("show-atsui");
  } else {
    tellOverlayText.textContent = "!?";
    tellOverlay.classList.add("show-rolling");
  }
}

let items = loadItems();
