      const parsed = JSON.parse(raw);
      if(Array.isArray(parsed) && parsed.length > 0){
        parsed.forEach(it=>{ if(!it.tell) it.tell = "none"; });
        return parsed;
      }
    }
  }catch(e){}
  return JSON.parse(JSON.stringify(DEFAULT_ITEMS));
}

