277	<body>
278	
279	<div id="tellOverlay"><div class="tell-text"></div></div>
280	
281	<h1>🎯 ルーレット作成アプリ</h1>
282	
283	<div class="layout">
284	
285	  <div class="wheel-side">
286	    <div class="wheel-wrap">
287	      <div id="pointer"></div>
288	      <canvas id="wheel" width="360" height="360"></canvas>
289	    </div>
290	    <button id="spinBtn">スピン！</button>
291	    <div id="result"></div>
292	
293	    <div class="sound-panel">
294	      <label><input type="checkbox" id="tellEnabled" checked> 先バレ演出</label>
295	      <label>🔊 <input type="range" id="tellVolume" min="0" max="100" value="70"></label>
296	    </div>
297	
298	    <div class="history">
299	      <h3>結果履歴</h3>
300	      <ul id="historyList"></ul>
301	    </div>
302	  </div>
303	
304	  <div class="panel">
305	    <h2>項目の設定</h2>
306	
307	    <div class="quick-row">
308	      <input type="number" id="quickCount" min="2" max="30" value="4">
309	      <button id="quickGenBtn">個数を指定して作り直す</button>
310	    </div>
311	
312	    <div id="itemList"></div>
313	
314	    <div class="add-row">
315	      <button id="addBtn">＋ 項目を追加</button>
316	      <button id="resetBtn" style="background:var(--panel2);color:var(--text);border:1px solid var(--border);">初期化</button>
317	    </div>
318	
319	    <div class="total-note" id="totalNote"></div>
320	  </div>
321	
322	</div>
323	
324	<script>
325	(function(){
326	  const STORAGE_KEY = "roulette_items_v1";
327	  const listEl = document.getElementById("itemList");
328	  const canvas = document.getElementById("wheel");
329	  const ctx = canvas.getContext("2d");
330	  const spinBtn = document.getElementById("spinBtn");
331	  const resultEl = document.getElementById("result");
332	  const historyList = document.getElementById("historyList");
333	  const totalNote = document.getElementById("totalNote");
334	
335	  const DEFAULT_ITEMS = [
336	    {name:"当たり", weight:1, tell:"rolling"},
337	    {name:"はずれ", weight:3, tell:"none"},
338	    {name:"もう一回", weight:2, tell:"rolling"},
339	    {name:"大当たり", weight:1, tell:"atsui"},
340	  ];
341	
342	  const TELL_SOUNDS = {
343	    none:   { label:"なし",             src:null },
344	    rolling:{ label:"ローリング(通常)",  src:"audio/index2_rolling.mp3" },
345	    atsui:  { label:"激熱(ポキューン)",  src:"audio/pokyun_atsui.mp3" },
346	  };
347	  const tellAudioCache = {};
348	  function getTellAudio(key){
349	    if(key === "none") return null;
350	    if(!tellAudioCache[key]){
351	      tellAudioCache[key] = new Audio(TELL_SOUNDS[key].src);
352	      tellAudioCache[key].preload = "auto";
353	    }
354	    return tellAudioCache[key];
355	  }
356	
357	  const tellEnabledEl = document.getElementById("tellEnabled");
358	  const tellVolumeEl = document.getElementById("tellVolume");
359	  const tellOverlay = document.getElementById("tellOverlay");
360	  const tellOverlayText = tellOverlay.querySelector(".tell-text");
361	
362	  function playTell(key){
363	    if(key === "none" || !tellEnabledEl.checked) return;
364	    const audio = getTellAudio(key);
365	    if(!audio) return;
366	    audio.volume = Number(tellVolumeEl.value) / 100;
367	    audio.currentTime = 0;
368	    audio.play().catch(()=>{});
369	
370	    tellOverlay.classList.remove("show-rolling","show-atsui");
371	    void tellOverlay.offsetWidth; // restart animation
372	    if(key === "atsui"){
373	      tellOverlayText.textContent = "熱っ!?";
374	      tellOverlay.classList.add("show-atsui");
375	    } else {
376	      tellOverlayText.textContent = "!?";
377	      tellOverlay.classList.add("show-rolling");
378	    }
379	  }
380	
381	  let items = loadItems();
382	  let rotation = 0;       // current wheel rotation (radians)
383	  let spinning = false;
384	
385	  function loadItems(){
386	    try{
387	      const raw = localStorage.getItem(STORAGE_KEY);
388	      if(raw){
389	        const parsed = JSON.parse(raw);
390	        if(Array.isArray(parsed) && parsed.length > 0){
391	          parsed.forEach(it=>{ if(!it.tell) it.tell = "none"; });
392	          return parsed;
393	        }
394	      }
395	    }catch(e){}
396	    return JSON.parse(JSON.stringify(DEFAULT_ITEMS));
397	  }
398	
399	  function saveItems(){
400	    localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
401	  }
402	
403	  function colorFor(i, total){
404	    const hue = Math.round((360 / Math.max(total,1)) * i);
405	    return `hsl(${hue}, 70%, 55%)`;
406	  }
407	
408	  function totalWeight(){
409	    return items.reduce((s,it)=> s + (Number(it.weight) > 0 ? Number(it.weight) : 0), 0);
410	  }
411	
412	  function renderList(){
413	    listEl.innerHTML = "";
414	    const total = totalWeight();
415	    items.forEach((item, i)=>{
416	      const row = document.createElement("div");
417	      row.className = "item-row";
418	
419	      const sw = document.createElement("div");
420	      sw.className = "swatch";
421	      sw.style.background = colorFor(i, items.length);
422	      row.appendChild(sw);
423	
424	      const nameInput = document.createElement("input");
425	      nameInput.type = "text";
426	      nameInput.value = item.name;
427	      nameInput.placeholder = "項目名";
428	      nameInput.addEventListener("input", ()=>{
429	        item.name = nameInput.value;
430	        saveItems();
431	        drawWheel();
432	      });
433	      row.appendChild(nameInput);
434	
435	      const weightInput = document.createElement("input");
436	      weightInput.type = "number";
437	      weightInput.min = "0";
438	      weightInput.step = "1";
439	      weightInput.value = item.weight;
440	      weightInput.title = "確率の重み";
441	      weightInput.addEventListener("input", ()=>{
442	        let v = parseFloat(weightInput.value);
443	        if(isNaN(v) || v < 0) v = 0;
444	        item.weight = v;
445	        saveItems();
446	        drawWheel();
447	        renderPercentages();
448	      });
449	      row.appendChild(weightInput);
450	
451	      const pct = document.createElement("div");
452	      pct.className = "pct";
453	      pct.dataset.pct = "1";
454	      row.appendChild(pct);
455	
456	      const tellSelect = document.createElement("select");
457	      tellSelect.className = "tell-select";
458	      Object.keys(TELL_SOUNDS).forEach(key=>{
459	        const opt = document.createElement("option");
460	        opt.value = key;
461	        opt.textContent = TELL_SOUNDS[key].label;
462	        if((item.tell || "none") === key) opt.selected = true;
463	        tellSelect.appendChild(opt);
464	      });
465	      tellSelect.addEventListener("change", ()=>{
466	        item.tell = tellSelect.value;
467	        saveItems();
468	      });
469	      row.appendChild(tellSelect);
470	
471	      const delBtn = document.createElement("button");
472	      delBtn.className = "del-btn";
473	      delBtn.textContent = "×";
474	      delBtn.title = "削除";
475	      delBtn.addEventListener("click", ()=>{
476	        if(items.length <= 2){
477	          alert("最低2項目は必要です。");
478	          return;
479	        }
480	        items.splice(i,1);
481	        saveItems();
482	        renderList();
483	        drawWheel();
484	      });
485	      row.appendChild(delBtn);
486	
487	      listEl.appendChild(row);
488	    });
489	    renderPercentages();
490	  }
491	
492	  function renderPercentages(){
493	    const total = totalWeight();
494	    const rows = listEl.querySelectorAll(".item-row");
495	    rows.forEach((row, i)=>{
496	      const pctEl = row.querySelector(".pct");
497	      const w = Number(items[i].weight) || 0;
498	      const pct = total > 0 ? (w/total*100) : 0;
499	      pctEl.textContent = pct.toFixed(1) + "%";
500	    });
501	    totalNote.textContent = `項目数: ${items.length} / 重み合計: ${total}`;
502	  }
503	
504	  function drawWheel(){
505	    const w = canvas.width, h = canvas.height;
506	    const cx = w/2, cy = h/2, r = w/2 - 4;
507	    ctx.clearRect(0,0,w,h);
508	
509	    ctx.save();
510	    ctx.translate(cx, cy);
511	    ctx.rotate(rotation);
512	
513	    const total = totalWeight();
514	    let startAngle = -Math.PI/2; // start at top
515	
516	    if(total <= 0){
517	      ctx.beginPath();
518	      ctx.arc(0,0,r,0,Math.PI*2);
519	      ctx.fillStyle = "#2a2e3c";
520	      ctx.fill();
521	    } else {
522	      items.forEach((item, i)=>{
523	        const w_ = Number(item.weight) > 0 ? Number(item.weight) : 0;
524	        const angle = (w_/total) * Math.PI*2;
525	        if(angle <= 0) return;
526	        const endAngle = startAngle + angle;
527	
528	        ctx.beginPath();
529	        ctx.moveTo(0,0);
530	        ctx.arc(0,0,r,startAngle,endAngle);
531	        ctx.closePath();
532	        ctx.fillStyle = colorFor(i, items.length);
533	        ctx.fill();
534	        ctx.strokeStyle = "rgba(0,0,0,0.25)";
535	        ctx.lineWidth = 2;
536	        ctx.stroke();
537	
538	        // label
539	        const mid = startAngle + angle/2;
540	        ctx.save();
541	        ctx.rotate(mid);
542	        ctx.textAlign = "right";
543	        ctx.textBaseline = "middle";
544	        ctx.fillStyle = "#fff";
545	        ctx.font = "bold 15px sans-serif";
546	        ctx.shadowColor = "rgba(0,0,0,.6)";
547	        ctx.shadowBlur = 3;
548	        const label = item.name && item.name.trim() ? item.name : "(無題)";
549	        ctx.fillText(truncateLabel(ctx, label, r-30), r-16, 0);
550	        ctx.restore();
551	
552	        startAngle = endAngle;
553	      });
554	    }
555	
556	    // center hub
557	    ctx.beginPath();
558	    ctx.arc(0,0,20,0,Math.PI*2);
559	    ctx.fillStyle = "#1a1c24";
560	    ctx.fill();
561	    ctx.lineWidth = 3;
562	    ctx.strokeStyle = "#444a5e";
563	    ctx.stroke();
564	
565	    ctx.restore();
566	  }
567	
568	  function truncateLabel(ctx, text, maxWidth){
569	    if(ctx.measureText(text).width <= maxWidth) return text;
570	    let t = text;
571	    while(t.length > 1 && ctx.measureText(t + "…").width > maxWidth){
572	      t = t.slice(0, -1);
573	    }
574	    return t + "…";
575	  }
576	
577	  function pickWeightedIndex(){
578	    const total = totalWeight();
579	    if(total <= 0) return Math.floor(Math.random()*items.length);
580	    let r = Math.random() * total;
581	    for(let i=0;i<items.length;i++){
582	      const w = Number(items[i].weight) > 0 ? Number(items[i].weight) : 0;
583	      if(r < w) return i;
584	      r -= w;
585	    }
586	    return items.length - 1;
587	  }
588	
589	  function easeOutQuint(t){
590	    return 1 - Math.pow(1-t, 5);
591	  }
592	
593	  function spin(){
594	    if(spinning) return;
595	    const total = totalWeight();
596	    if(total <= 0){
597	      alert("重みの合計が0です。少なくとも1項目に重みを設定してください。");
598	      return;
599	    }
600	    spinning = true;
601	    spinBtn.disabled = true;
602	    resultEl.textContent = "";
603	
604	    const winnerIndex = pickWeightedIndex();
605	
606	    // compute mid-angle of winner segment in wheel's own (unrotated) coordinate space
607	    let startAngle = -Math.PI/2;
608	    let winnerStart = 0, winnerAngle = 0;
609	    for(let i=0;i<items.length;i++){
610	      const w_ = Number(items[i].weight) > 0 ? Number(items[i].weight) : 0;
611	      const angle = (w_/total) * Math.PI*2;
612	      if(i === winnerIndex){
613	        winnerStart = startAngle;
614	        winnerAngle = angle;
615	        break;
616	      }
617	      startAngle += angle;
618	    }
619	    // land somewhere inside segment (not exactly on edge)
620	    const margin = winnerAngle * 0.15;
621	    const landOffset = margin + Math.random() * (winnerAngle - margin*2);
622	    const targetMidUnrotated = winnerStart + landOffset;
623	
624	    // we want: targetMidUnrotated + finalRotation ≡ -PI/2 (pointer position), mod 2PI
625	    const TWO_PI = Math.PI*2;
626	    let delta = (-Math.PI/2 - targetMidUnrotated) - (rotation % TWO_PI);
627	    delta = ((delta % TWO_PI) + TWO_PI) % TWO_PI; // normalize to [0, 2PI)
628	
629	    const extraSpins = 5 + Math.floor(Math.random()*3); // 5~7 full turns
630	    const totalDelta = delta + extraSpins * TWO_PI;
631	
632	    const startRotation = rotation;
633	    const endRotation = rotation + totalDelta;
634	    const duration = 4200;
635	    const startTime = performance.now();
636	
637	    // 先バレ: fire partway through the spin, before it visually settles
638	    const tellKey = items[winnerIndex].tell || "none";
639	    setTimeout(()=> playTell(tellKey), duration * 0.6);
640	
641	    function frame(now){
642	      const t = Math.min(1, (now - startTime) / duration);
643	      const eased = easeOutQuint(t);
644	      rotation = startRotation + (endRotation - startRotation) * eased;
645	      drawWheel();
646	      if(t < 1){
647	        requestAnimationFrame(frame);
648	      }else{
649	        rotation = endRotation;
650	        drawWheel();
651	        finishSpin(winnerIndex);
652	      }
653	    }
654	    requestAnimationFrame(frame);
655	  }
656	
657	  function finishSpin(winnerIndex){
658	    spinning = false;
659	    spinBtn.disabled = false;
660	    const name = items[winnerIndex].name && items[winnerIndex].name.trim() ? items[winnerIndex].name : "(無題)";
661	    resultEl.textContent = "🎉 結果: " + name;
662	
663	    const li = document.createElement("li");
664	    const time = new Date().toLocaleTimeString();
665	    li.textContent = `${time} - ${name}`;
666	    historyList.insertBefore(li, historyList.firstChild);
667	    while(historyList.children.length > 20){
668	      historyList.removeChild(historyList.lastChild);
669	    }
670	  }
671	
672	  document.getElementById("addBtn").addEventListener("click", ()=>{
673	    items.push({name:"項目" + (items.length+1), weight:1, tell:"none"});
674	    saveItems();
675	    renderList();
676	    drawWheel();
677	  });
678	
679	  document.getElementById("resetBtn").addEventListener("click", ()=>{
680	    if(!confirm("項目を初期状態に戻しますか？")) return;
681	    items = JSON.parse(JSON.stringify(DEFAULT_ITEMS));
682	    saveItems();
683	    renderList();
684	    drawWheel();
685	  });
686	
687	  document.getElementById("quickGenBtn").addEventListener("click", ()=>{
688	    let n = parseInt(document.getElementById("quickCount").value, 10);
689	    if(isNaN(n) || n < 2) n = 2;
690	    if(n > 30) n = 30;
691	    items = [];
692	    for(let i=0;i<n;i++){
693	      items.push({name:"項目" + (i+1), weight:1, tell:"none"});
694	    }
695	    saveItems();
696	    renderList();
697	    drawWheel();
698	  });
699	
700	  spinBtn.addEventListener("click", spin);
701	
702	  renderList();
703	  drawWheel();
704	})();
705	</script>
