input.old_string:
const DEFAULT_ITEMS = [
  {name:"当たり", weight:1, tell:"rolling"},
  {name:"はずれ", weight:3, tell:"none"},
  {name:"もう一回", weight:2, tell:"rolling"},
  {name:"大当たり", weight:1, tell:"atsui"},
];

const TELL_SOUNDS = {
  none:   { label:"なし",             src:null },
  rolling:{ label:"ローリング(通常)",  src:"audio/index2_rolling.mp3" },
  atsui:  { label:"激熱(ポキューン)",  src:"audio/pokyun_atsui.mp3" },
};
const tellAudioCache = {};
function getTellAudio(key){
  if(key === "none") return null;
  if(!tellAudioCache[key]){
    tellAudioCache[key] = new Audio(TELL_SOUNDS[key].src);
    tellAudioCache[key].preload = "auto";
  }
  return tellAudioCache[key];
}

const tellEnabledEl = document.getElementById("tellEnabled");
const tellVolumeEl = document.getElementById("tellVolume");
const tellOverlay = document.getElementById("tellOverlay");
const tellOverlayText = tellOverlay.querySelector(".tell-text");

function playTell(key){
  if(key === "none" || !tellEnabledEl.checked) return;
  const audio = getTellAudio(key);
  if(!audio) return;
  audio.volume = Number(tellVolumeEl.value) / 100;
  audio.currentTime = 0;
  audio.play().catch(()=>{});

  tellOverlay.classList.remove("show-rolling","show-atsui");
  void tellOverlay.offsetWidth; // restart animation
  if(key === "atsui"){
    tellOverlayText.textContent = "熱っ!?";
    tellOverlay.classList.add("show-atsui");
  } else {
    tellOverlayText.textContent = "!?";
    tellOverlay.classList.add("show-rolling");
  }
}

input.new_string:
const DEFAULT_ITEMS = [
  {name:"当たり", weight:1, rank:"normal"},
  {name:"はずれ", weight:3, rank:"normal"},
  {name:"もう一回", weight:2, rank:"normal"},
  {name:"大当たり", weight:1, rank:"premium"},
];

// 白/赤/虹の3段階。音源は手持ちの2素材を音量差で使い回す。
const TELL_COLORS = {
  white:  { label:"白(低信頼)", src:"audio/index2_rolling.mp3", volumeScale:0.35 },
  red:    { label:"赤(中信頼)", src:"audio/index2_rolling.mp3", volumeScale:0.8 },
  rainbow:{ label:"虹(高信頼)", src:"audio/pokyun_atsui.mp3",  volumeScale:1.0 },
};
const tellAudioCache = {};
function getTellAudio(color){
  if(!tellAudioCache[color]){
    tellAudioCache[color] = new Audio(TELL_COLORS[color].src);
    tellAudioCache[color].preload = "auto";
  }
  return tellAudioCache[color];
}

const tellEnabledEl = document.getElementById("tellEnabled");
const tellVolumeEl = document.getElementById("tellVolume");
const tellRateEl = document.getElementById("tellRate");
const tellRateLabel = document.getElementById("tellRateLabel");
const tellOverlay = document.getElementById("tellOverlay");
const tellOverlayText = tellOverlay.querySelector(".tell-text");

tellRateEl.addEventListener("input", ()=>{
  tellRateLabel.textContent = tellRateEl.value + "%";
});

// 実機の「先バレ」を再現: 毎回は出ない/色ごとに信頼度が違う/ガセもある
function decideTellColor(winnerIndex){
  if(Math.random()*100 > Number(tellRateEl.value)) return null; // この回は先バレ自体が発生しない
  const rank = items[winnerIndex].rank || "normal";
  const roll = Math.random();
  if(rank === "premium"){
    // 激アツ項目: 虹が出やすいが、白で終わることもある
    if(roll < 0.60) return "rainbow";
    if(roll < 0.90) return "red";
    return "white";
  } else {
    // 通常項目: 基本は白/赤だが、ごく低確率で虹のガセが出る
    if(roll < 0.55) return "white";
    if(roll < 0.92) return "red";
    return "rainbow";
  }
}

function playTell(color){
  if(!color || !tellEnabledEl.checked) return;
  const audio = getTellAudio(color);
  audio.volume = (Number(tellVolumeEl.value) / 100) * TELL_COLORS[color].volumeScale;
  audio.currentTime = 0;
  audio.play().catch(()=>{});

  tellOverlay.classList.remove("show-white","show-red","show-rainbow");
  void tellOverlay.offsetWidth; // restart animation
  tellOverlay.classList.add("show-" + color);
  tellOverlayText.textContent = color === "rainbow" ? "激熱!?" : (color === "red" ? "!?" : "?");
}

