const winnerIndex = pickWeightedIndex();

// compute mid-angle of winner segment in wheel's own (unrotated) coordinate space
let startAngle = -Math.PI/2;
let winnerStart = 0, winnerAngle = 0;
for(let i=0;i<items.length;i++){
  const w_ = Number(items[i].weight) > 0 ? Number(items[i].weight) : 0;
  const angle = (w_/total) * Math.PI*2;
  if(i === winnerIndex){
    winnerStart = startAngle;
    winnerAngle = angle;
    break;
  }
  startAngle += angle;
}
// land somewhere inside segment (not exactly on edge)
const margin = winnerAngle * 0.15;
const landOffset = margin + Math.random() * (winnerAngle - margin*2);
const targetMidUnrotated = winnerStart + landOffset;

// we want: targetMidUnrotated + finalRotation ≡ -PI/2 (pointer position), mod 2PI
const TWO_PI = Math.PI*2;
let delta = (-Math.PI/2 - targetMidUnrotated) - (rotation % TWO_PI);
delta = ((delta % TWO_PI) + TWO_PI) % TWO_PI; // normalize to [0, 2PI)

const extraSpins = 5 + Math.floor(Math.random()*3); // 5~7 full turns
const totalDelta = delta + extraSpins * TWO_PI;

const startRotation = rotation;
const endRotation = rotation + totalDelta;
const duration = 4200;
const startTime = performance.now();

// 先バレ: 保留(スピン)が始まった瞬間に発生する演出
const tellColor = decideTellColor(winnerIndex);
playTell(tellColor);

function frame(now){
  const t = Math.min(1, (now - startTime) / duration);
  const eased = easeOutQuint(t);
  rotation = startRotation + (endRotation - startRotation) * eased;
  drawWheel();
  if(t < 1){
    requestAnimationFrame(frame);
  }else{
    rotation = endRotation;
    drawWheel();
    finishSpin(winnerIndex);
  }

