const tellRateEl = document.getElementById("tellRate");
const tellRateLabel = document.getElementById("tellRateLabel");
const fakeRateEl = document.getElementById("fakeRate");
const fakeRateLabel = document.getElementById("fakeRateLabel");
const tellOverlay = document.getElementById("tellOverlay");
const tellOverlayText = tellOverlay.querySelector(".tell-text");

tellRateEl.addEventListener("input", ()=>{
  tellRateLabel.textContent = tellRateEl.value + "%";
});
fakeRateEl.addEventListener("input", ()=>{
  fakeRateLabel.textContent = fakeRateEl.value + "%";
});

// 先バレ: 発生率の抽選に外れたら鳴らない。さらに「ガセ」で、本来は激熱でない結果でも
// まれに激熱演出だけ出ることがある(=鳴っても当たるとは限らない)。
function decideTell(winnerIndex){
  let key = items[winnerIndex].tell || "none";
  if(key !== "atsui" && Math.random()*100 < Number(fakeRateEl.value)){
    key = "atsui";
  }
  if(key === "none") return null;
  if(Math.random()*100 > Number(tellRateEl.value)) return null;
  return key;
}
